def test_merge_hypotheses_appends_distinct():
    assert _merge_hypotheses([{"id": "h1"}], [{"id": "h2"}]) == [{"id": "h1"}, {"id": "h2"}]


def test_merge_hypotheses_dedups_by_id_latest_wins():
    assert _merge_hypotheses([{"id": "h1", "v": 1}], [{"id": "h1", "v": 2}]) == [{"id": "h1", "v": 2}]


def test_merge_hypotheses_dedups_by_hypothesis_id():
    # pass-7: the canonical id field is 'hypothesis_id' (FormalHypothesis / SAP);
    # keying on 'id' alone silently never matched.
    out = _merge_hypotheses([{"hypothesis_id": "H1.1", "v": 1}], [{"hypothesis_id": "H1.1", "v": 2}])
    assert out == [{"hypothesis_id": "H1.1", "v": 2}]

