def test_merge_hypotheses_ignores_non_dict_entries():
    # Non-dict entries are kept as-is, not crashed on.
    assert _merge_hypotheses([], ["not-a-dict", {"hypothesis_id": "H1.1"}]) == [
        "not-a-dict", {"hypothesis_id": "H1.1"}]


def test_merge_hypotheses_keeps_entries_without_id():
    assert _merge_hypotheses([], [{"x": 1}, {"x": 2}]) == [{"x": 1}, {"x": 2}]


def test_merge_hypotheses_preserves_position_on_update():
    out = _merge_hypotheses([{"id": "a"}, {"id": "b"}], [{"id": "a", "u": 1}])
    assert out == [{"id": "a", "u": 1}, {"id": "b"}]


def test_merge_hypotheses_is_batching_invariant():
    # Merging in one batch == merging incrementally.
    one = _merge_hypotheses([{"id": "a"}], [{"id": "b"}, {"id": "a", "u": 1}])
    two = _merge_hypotheses(_merge_hypotheses([{"id": "a"}], [{"id": "b"}]), [{"id": "a", "u": 1}])
    assert one == two == [{"id": "a", "u": 1}, {"id": "b"}]
